import{_ as e,o as r,c as t,a7 as s}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Card System","description":"","frontmatter":{},"headers":[],"relativePath":"en/cards/index.md","filePath":"en/cards/index.md","lastUpdated":1775394001000}'),i={name:"en/cards/index.md"};function n(d,a,o,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="card-system" tabindex="-1">Card System <a class="header-anchor" href="#card-system" aria-label="Permalink to &quot;Card System&quot;">​</a></h1><p>The card system is the core of Morimens&#39; combat. Awakeners use cards to attack, defend, buff, and unleash devastating abilities. The game features <strong>185+ cards</strong> across all realms and types.</p><h2 id="card-types" tabindex="-1">Card Types <a class="header-anchor" href="#card-types" aria-label="Permalink to &quot;Card Types&quot;">​</a></h2><h3 id="command-cards" tabindex="-1">Command Cards <a class="header-anchor" href="#command-cards" aria-label="Permalink to &quot;Command Cards&quot;">​</a></h3><p><span class="card-type-badge card-command">Command</span></p><p>Each Awakener has <strong>4 Command Cards</strong> that form the backbone of their kit. These are drawn into your hand during battle and played by spending Arithmetica.</p><h3 id="spirit-awakening-cards" tabindex="-1">Spirit Awakening Cards <a class="header-anchor" href="#spirit-awakening-cards" aria-label="Permalink to &quot;Spirit Awakening Cards&quot;">​</a></h3><p><span class="card-type-badge card-spirit">Spirit Awakening</span></p><p>Each Awakener has <strong>1 Spirit Awakening Card</strong> — a powerful signature ability. Spirit Awakening Cards are typically high-impact plays that define the Awakener&#39;s playstyle.</p><h3 id="madness-burst" tabindex="-1">Madness Burst <a class="header-anchor" href="#madness-burst" aria-label="Permalink to &quot;Madness Burst&quot;">​</a></h3><p><span class="card-type-badge card-madness">Madness Burst</span></p><p>When an Awakener&#39;s <strong>Madness Points</strong> reach <strong>100</strong>, a Madness Burst is triggered <strong>for free</strong> (costs no Arithmetica). This is an automatic, powerful ability that can turn the tide of battle.</p><h2 id="arithmetica-算力" tabindex="-1">Arithmetica (算力) <a class="header-anchor" href="#arithmetica-算力" aria-label="Permalink to &quot;Arithmetica (算力)&quot;">​</a></h2><p><span class="arithmetica-cost">Arithmetica</span> is the energy system used to play cards.</p><ul><li>You receive <strong>5 Arithmetica per turn</strong>.</li><li>Each card has an Arithmetica cost displayed on it.</li><li>Managing your Arithmetica budget across your hand is key to optimal play.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Not all cards need to be played every turn. Holding cards for a better turn or saving Arithmetica for a high-cost Spirit Awakening Card is often the correct play.</p></div><h2 id="madness-points-狂气" tabindex="-1">Madness Points (狂气) <a class="header-anchor" href="#madness-points-狂气" aria-label="Permalink to &quot;Madness Points (狂气)&quot;">​</a></h2><ul><li>Madness Points build up during combat through taking damage and playing certain cards.</li><li>At <strong>100 Madness Points</strong>, the Awakener&#39;s Madness Burst triggers automatically and for free.</li><li>After triggering, Madness Points reset to 0 and begin building again.</li></ul><h2 id="silver-key" tabindex="-1">Silver Key <a class="header-anchor" href="#silver-key" aria-label="Permalink to &quot;Silver Key&quot;">​</a></h2><ul><li>Silver Key energy accumulates during battle.</li><li>At <strong>1000 Silver Key</strong>, you can activate a <strong>Key Order</strong> — a powerful ability tied to your equipped Key Order card.</li><li>See <a href="./../key-orders/">Key Orders</a> for details.</li></ul><h2 id="card-count" tabindex="-1">Card Count <a class="header-anchor" href="#card-count" aria-label="Permalink to &quot;Card Count&quot;">​</a></h2><p>Morimens features <strong>185+ cards</strong> across all Awakeners and realms, with more added as new characters are released.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./list.html">Card List</a></li><li><a href="./upgrade.html">Card Upgrades</a></li><li><a href="./deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../realms/">Realms Overview</a></li></ul>',24)])])}const u=e(i,[["render",n]]);export{m as __pageData,u as default};
